const input = $input.first().json;
const posts = input.posts || [];
if (posts.length === 0) {
  return [];
}
return posts.map(post => ({ json: post }));

const items = $input.all();
const posts = items.map(item => ({
  id: item.json.postId,
  text: item.json.postText,
  author: item.json.authorName
}));
const batchMessage = JSON.stringify(posts);

const systemPrompt = 'You are a lead qualification expert for a Family Law Attorney in Israel.\nYou read Hebrew fluently and understand conversational, colloquial, and formal Hebrew.\n\nA LEAD is a Facebook post where a real person is actively seeking help related to:\n- Divorce or separation (\u05d2\u05d9\u05e8\u05d5\u05e9\u05d9\u05df, \u05e4\u05e8\u05d9\u05d3\u05d4)\n- Child custody disputes (\u05de\u05e9\u05de\u05d5\u05e8\u05ea \u05d9\u05dc\u05d3\u05d9\u05dd)\n- Alimony or financial disputes in marriage (\u05de\u05d6\u05d5\u05e0\u05d5\u05ea, \u05d4\u05e1\u05db\u05dd \u05de\u05de\u05d5\u05df)\n- Restraining orders or domestic violence (\u05e6\u05d5 \u05d4\u05d2\u05e0\u05d4, \u05d0\u05dc\u05d9\u05de\u05d5\u05ea \u05d1\u05de\u05e9\u05e4\u05d7\u05d4)\n- Family legal advice requests (\u05d9\u05d9\u05e2\u05d5\u05e5 \u05de\u05e9\u05e4\u05d8\u05d9 \u05de\u05e9\u05e4\u05d7\u05ea\u05d9)\n- Property disputes in marriage or divorce (\u05d7\u05dc\u05d5\u05e7\u05ea \u05e8\u05db\u05d5\u05e9)\n\nNOT a lead:\n- Posts offering legal services (attorneys advertising)\n- General news, opinion, or informational posts\n- Posts that mention these topics without expressing a personal need\n- Spam, promotions, or unrelated content\n\nRespond ONLY with valid JSON in this exact format:\n{"relevant_post_ids": ["id1", "id2"]}\n\nIf no posts are relevant, return: {"relevant_post_ids": []}';

const requestBody = JSON.stringify({
  model: 'claude-3-5-sonnet-20241022',
  max_tokens: 512,
  system: systemPrompt,
  messages: [{ role: 'user', content: batchMessage }]
});

return [{
  json: {
    originalItems: items.map(i => i.json),
    requestBody
  }
}];

const responseText = $input.first().json.content[0].text;
const originalItems = $('Build Batch Message').first().json.originalItems;

let parsed;
try {
  parsed = JSON.parse(responseText);
} catch (e) {
  throw new Error('Claude returned malformed JSON: ' + responseText.substring(0, 200));
}

const relevantIds = parsed.relevant_post_ids;
if (!Array.isArray(relevantIds)) {
  throw new Error('Claude response missing relevant_post_ids array: ' + responseText.substring(0, 200));
}

if (relevantIds.length === 0) {
  return [];
}

const idSet = new Set(relevantIds);
const filtered = originalItems.filter(item => idSet.has(item.postId));
return filtered.map(item => ({ json: item }));
